'use strict';

// Build a small task-local context bundle for workers/reviewers.
// The bundle is intentionally conservative: include payload essentials and only
// the context_refs slices that the task explicitly names.

const fs = require('fs');
const path = require('path');

function stripAnchor(ref) {
  const idx = ref.indexOf('#');
  if (idx === -1) return { file: ref, anchor: null };
  return { file: ref.slice(0, idx), anchor: ref.slice(idx + 1) };
}

function normalizeHeadingText(s) {
  return s.toLowerCase().replace(/[^a-z0-9가-힣/._ -]+/gi, '').replace(/\s+/g, ' ').trim();
}

function headingMatches(line, anchor) {
  const m = /^(#{1,6})\s+(.+)$/.exec(line);
  if (!m) return false;
  const title = normalizeHeadingText(m[2]);
  const wanted = normalizeHeadingText(decodeURIComponent(anchor));
  return title === wanted || title.includes(wanted) || wanted.includes(title);
}

function extractAnchoredSection(markdown, anchor) {
  if (!anchor) return markdown;
  const lines = markdown.split(/\r?\n/);
  let start = -1;
  let level = 0;

  for (let i = 0; i < lines.length; i++) {
    const m = /^(#{1,6})\s+(.+)$/.exec(lines[i]);
    if (m && headingMatches(lines[i], anchor)) {
      start = i;
      level = m[1].length;
      break;
    }
  }
  if (start === -1) return null;

  let end = lines.length;
  for (let i = start + 1; i < lines.length; i++) {
    const m = /^(#{1,6})\s+/.exec(lines[i]);
    if (m && m[1].length <= level) {
      end = i;
      break;
    }
  }
  return lines.slice(start, end).join('\n').trim();
}

function readContextRef(ref, opts = {}) {
  const cwd = opts.cwd || process.cwd();
  const { file, anchor } = stripAnchor(ref);
  const abs = path.join(cwd, file);
  if (!fs.existsSync(abs)) {
    return { ref, ok: false, error: 'missing file' };
  }
  const markdown = fs.readFileSync(abs, 'utf8');
  const content = extractAnchoredSection(markdown, anchor);
  if (content === null) {
    return { ref, ok: false, error: `anchor not found: ${anchor}` };
  }
  return { ref, ok: true, file, anchor, content };
}

function renderContextBundle(payload, opts = {}) {
  const refs = Array.isArray(payload.context_refs) ? payload.context_refs : [];
  const out = [];
  out.push(`# Worker Context Bundle — ${payload.task_id}`);
  out.push('');
  out.push('> Generated by pact. Prefer this file over reading long SOT documents.');
  out.push('');
  out.push('## Task');
  out.push('');
  out.push('```json');
  out.push(JSON.stringify({
    task_id: payload.task_id,
    title: payload.title,
    allowed_paths: payload.allowed_paths || [],
    forbidden_paths: payload.forbidden_paths || [],
    done_criteria: payload.done_criteria || [],
    verify_commands: payload.verify_commands || [],
    contracts: payload.contracts || {},
    tdd: !!payload.tdd,
    prd_reference: payload.prd_reference || null,
  }, null, 2));
  out.push('```');
  out.push('');

  out.push('## Context refs');
  out.push('');
  if (refs.length === 0) {
    out.push('(없음)');
  } else {
    for (const ref of refs) out.push(`- ${ref}`);
  }
  out.push('');

  out.push('## Slices');
  out.push('');
  for (const ref of refs) {
    const r = readContextRef(ref, opts);
    out.push(`### ${ref}`);
    out.push('');
    if (!r.ok) {
      out.push(`> ${r.error}`);
      out.push('');
      continue;
    }
    out.push(r.content);
    out.push('');
  }

  return out.join('\n').trimEnd() + '\n';
}

function writeContextBundle(payload, outPath, opts = {}) {
  fs.mkdirSync(path.dirname(outPath), { recursive: true });
  const content = renderContextBundle(payload, opts);
  fs.writeFileSync(outPath, content);
  return { path: outPath, content };
}

module.exports = {
  stripAnchor,
  extractAnchoredSection,
  readContextRef,
  renderContextBundle,
  writeContextBundle,
};
